import type { HTMLAttributes } from 'react';
import type { StepperDirectionType, StepType } from './common/step.types';
export interface StepperProps extends HTMLAttributes<HTMLDivElement> {
    /**
     * Прокрутка на указанное количество шагов.
     */
    switchLength?: number;
    /**
     * Массив объектов описывающих шаги.
     * @param id: string - Идентификатор шага.
     * @param label: string - Наименование шага.
     * @param signature?: string: - Верхний колонтитул шага.
     * @param state?: 'active' | 'success' | 'error' | 'disabled' | 'visited' | 'non-visited' - Статус шага - определяет форму и цвет иконки шага.
     * @param activated?: boolean - Состояние "активный" шага - определяет, какой шаг активен ("по которому был клик" - для нелинейного варианта отображения).
     * @param direction?: 'vertical' | 'horizontal' - Определяет отображение шага "в строку" / "в столбец".
     */
    steps: StepType[];
    /**
     * Идентификатор активного шага.
     */
    activeStepId: StepType['id'];
    /**
     * Определяет отображение компонента "в строку" / "в столбец".
     * Отображение "в столбец" недоступен для mobile = true
     */
    direction?: StepperDirectionType;
    /**
     * Определяет отображение компонента в строку в компактном формате (только иконка/ порядковый номер шага)
     */
    mobile?: boolean;
    /**
     * Пользовательский класс
     */
    className?: string;
    /**
     * Меняет шаг. Если метод не передается, то степпер будет считаться линейным.
     *
     * @param id - идентификатор шага.
     */
    onStepChange?: (id: string) => void;
    /**
     * включает/выключает автоскролл следование после переключения шага.
     * первый раз скролл отрабатывает всегда (при монтировании компоннета)
     * а последующие уже регулируются этим пропсом
     */
    enableAutoScroll?: boolean;
}
